import{_ as t,o,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"زمان‌بندی مرورگر (Browser Timings)","description":"","frontmatter":{},"headers":[],"relativePath":"fa/configuration/browser-timings.md","filePath":"fa/configuration/browser-timings.md"}'),i={name:"fa/configuration/browser-timings.md"};function n(c,e,s,d,m,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<div dir="rtl"><h1 id="زمان‌بندی-مرورگر-browser-timings" tabindex="-1"><i class="ph ph-clock-countdown"></i> زمان‌بندی مرورگر (Browser Timings) <a class="header-anchor" href="#زمان‌بندی-مرورگر-browser-timings" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-clock-countdown&quot;&gt;&lt;/i&gt; زمان‌بندی مرورگر (Browser Timings)&quot;">​</a></h1><p>این صفحه محدودیت‌های فنی معماری WebGL مربوط به پارامتر <code>Application.targetFrameRate</code> را به تفصیل شرح می‌دهد.</p><p>هنگامی که یک پروژه Unity برای WebGL کامپایل می‌شود، پارامتر <code>Application.targetFrameRate</code> تنها محدودیت داخلی فریم انجین را تغییر نمی‌دهد، بلکه <strong>API پایه مرورگر</strong> را که حلقه اصلی (Main Loop) از طریق آن اجرا می‌شود نیز تغییر می‌دهد.</p><h2 id="بدون-محدودیت-uncapped-requestanimationframe" tabindex="-1">بدون محدودیت (Uncapped) (requestAnimationFrame) <a class="header-anchor" href="#بدون-محدودیت-uncapped-requestanimationframe" aria-label="Permalink to &quot;بدون محدودیت (Uncapped) (requestAnimationFrame)&quot;">​</a></h2><p>اگر محدودیت نرخ فریم را حذف کنید (بسته به نسخه Unity، با تنظیم <code>Application.targetFrameRate</code> روی <code>-1</code> یا <code>0</code>)، کامپایلر Emscripten حلقه اصلی Unity را مستقیماً به API مرورگر یعنی <code>window.requestAnimationFrame</code> متصل می‌کند.</p><ul><li><strong>مزایا:</strong> این روان‌ترین، دقیق‌ترین و بومی‌ترین روش رندرینگ در وب است. مرورگر به‌طور خودکار این فراخوانی را با نرخ تازه‌سازی مانیتور بازیکن (VSync) همگام‌سازی (Sync) می‌کند.</li><li><strong>تحلیل:</strong> متریک‌های <code>cpuMainThreadFrameTime</code> (که توسط WebAP خوانده می‌شود) منعکس‌کننده زمان <strong>واقعی</strong> هستند که CPU صرف محاسبه فیزیک و اسکریپت‌ها کرده است.</li></ul><h2 id="محدود-شده-به‌صورت-مصنوعی-settimeout" tabindex="-1">محدود شده به‌صورت مصنوعی (setTimeout) <a class="header-anchor" href="#محدود-شده-به‌صورت-مصنوعی-settimeout" aria-label="Permalink to &quot;محدود شده به‌صورت مصنوعی (setTimeout)&quot;">​</a></h2><p>اگر به‌طور سخت‌گیرانه یک نرخ فریم خاص را تحمیل کنید (مثلاً <code>Application.targetFrameRate = 30</code>)، Emscripten مجبور می‌شود <code>requestAnimationFrame</code> را رها کند. در عوض، از API <code>setTimeout()</code> یا ترکیبات پیچیده‌ای از تایمرهای داخلی برای به تأخیر انداختن مصنوعی حلقه استفاده خواهد کرد.</p><div class="warning custom-block"><p class="custom-block-title">تحریف متریک‌های CPU (دام Emscripten)</p><p>تایمرهای مصنوعی باعث ایجاد تفاوت و خطای عظیمی در هنگام اندازه‌گیری زمان CPU می‌شوند. پردازنده ممکن است تمام محاسبات منطق بازی را در یک زمان بسیار سریعِ ۵ میلی‌ثانیه‌ای به پایان برساند و به حالت بیکاری (Idle) برود، اما کوروتین (Coroutine) <code>WaitForEndOfFrame</code> تا زمانی که تایمر <code>setTimeout</code> تمام نشود، از سر گرفته نخواهد شد.</p><p><strong>در نتیجه:</strong> ابزار <code>FrameTimingManager</code> این زمان انتظار را در داخل زمان‌بندی‌های CPU ثبت خواهد کرد. Profiler (و ابزار Tracker در WebAP) نتیجه می‌گیرند که شما با یک <em>گلوگاه پردازنده (CPU Bottleneck)</em> مواجه هستید، حتی اگر پردازنده به‌طور عملکردی بیکار باشد و فریم‌ها صرفاً در انتظار تایمر مرورگر باشند.</p></div><h2 id="استراتژی-پیکربندی-صحیح" tabindex="-1">استراتژی پیکربندی صحیح <a class="header-anchor" href="#استراتژی-پیکربندی-صحیح" aria-label="Permalink to &quot;استراتژی پیکربندی صحیح&quot;">​</a></h2><p>برای اینکه عملکرد تطبیقی وب (Web Adaptive Performance) در مرورگر به بهترین نحو کار کند:<br> ۱. <strong>از <code>Application.targetFrameRate</code> استفاده نکنید</strong>. آن را روی <code>-1</code> (بدون محدودیت) بگذارید.<br> ۲. FPS مورد نظر خود را در تنظیمات افزونه مشخص کنید (<code>Target Min FPS = 60</code>). WebAP از این مقدار به‌عنوان یک محدودیت سخت استفاده نمی‌کند، بلکه آن را به‌عنوان پایه‌ای برای تصمیم‌گیری در مورد کیفیت رندر در نظر می‌گیرد.</p></div>',1)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
